CREATE TABLE IF NOT EXISTS test_item_prd_goal_link (
  project_code VARCHAR(64) NOT NULL DEFAULT 'fitness-agent',
  link_id VARCHAR(16) PRIMARY KEY,
  item_id VARCHAR(64) NOT NULL REFERENCES test_item_detail(item_id) ON DELETE CASCADE, prd_goal_id VARCHAR(8) NOT NULL REFERENCES prd_goal(prd_goal_id), is_primary BOOLEAN DEFAULT FALSE
);
CREATE INDEX IF NOT EXISTS idx_test_item_prd_goal_link_item ON test_item_prd_goal_link(item_id);

